mapper.select:
SELECT * FROM chuyen_xe
WHERE ma_tuyen = #{maTuyen} AND ma_xe = #{maXe} AND thoi_diem_khoi_hanh = #{thoiDiemKhoiHanh}
AND ma != #{maLoaiTru}
LIMIT 1

SELECT ma_ghe_ngoi FROM ve_xe
WHERE ma_chuyen = #{maChuyen}
  AND UPPER(trang_thai) NOT IN ('CANCELLED', 'EXPIRED')

SELECT COUNT(*) FROM chuyen_xe
WHERE DATE(thoi_diem_khoi_hanh) = #{ngay}
AND ma_tuyen = #{maTuyen}

mapper.update:
UPDATE chuyen_xe SET ma_tuyen = #{maTuyen}, ma_xe = #{maXe}, thoi_diem_khoi_hanh = #{thoiDiemKhoiHanh},
    thoi_diem_den = #{thoiDiemDen}, gia_ve = #{giaVe}, trang_thai = #{trangThai}
WHERE ma = #{ma}
